-- Create "businesses" table
CREATE TABLE "businesses" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "category" character varying NOT NULL DEFAULT 'others', "name" character varying NOT NULL, "logo_url" character varying NOT NULL, "email" character varying NOT NULL, "website" character varying NOT NULL, "disabled" boolean NOT NULL DEFAULT true, "disabled_at" timestamptz NOT NULL, "disable_reason" character varying NOT NULL, "verified" boolean NOT NULL DEFAULT false, "verified_at" timestamptz NOT NULL, "created_at" timestamptz NOT NULL, PRIMARY KEY ("id"));
-- Create index "businesses_name_key" to table: "businesses"
CREATE UNIQUE INDEX "businesses_name_key" ON "businesses" ("name");
-- Modify "users" table
ALTER TABLE "users" ADD COLUMN "created_at" timestamptz NOT NULL;
-- Create "managers" table
CREATE TABLE "managers" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "created_at" timestamptz NOT NULL, "position" character varying NOT NULL, "diasbled" boolean NOT NULL DEFAULT false, "disable_reason" character varying NOT NULL, "disabled_at" timestamptz NOT NULL, "business_business_manager" bigint NOT NULL, "user_user_manager" bigint NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "managers_businesses_business_manager" FOREIGN KEY ("business_business_manager") REFERENCES "businesses" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION, CONSTRAINT "managers_users_user_manager" FOREIGN KEY ("user_user_manager") REFERENCES "users" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION);
-- Create "socials" table
CREATE TABLE "socials" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "created_at" timestamptz NOT NULL, "name" character varying NOT NULL, "url" character varying NOT NULL, "business_business_social" bigint NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "socials_businesses_business_social" FOREIGN KEY ("business_business_social") REFERENCES "businesses" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION);
